function projectEditUrl(projectId) {
    return `/gestio/projectes/modifica-projecte/${encodeURIComponent(String(projectId))}`;
}
function el(id) {
    return document.getElementById(id);
}
function esc(s) {
    return s.replace(/[&<>"']/g, (c) => {
        switch (c) {
            case '&':
                return '&amp;';
            case '<':
                return '&lt;';
            case '>':
                return '&gt;';
            case '"':
                return '&quot;';
            case "'":
                return '&#039;';
            default:
                return c;
        }
    });
}
function taskStatusLabel(n) {
    switch (n) {
        case 1:
            return 'Backlog';
        case 2:
            return 'En curs';
        case 3:
            return 'Bloquejada';
        case 4:
            return 'Feta';
        default:
            return '—';
    }
}
function prioLabel(n) {
    // Ajusta si usas 1..3 o 1..5
    switch (n) {
        case 1:
            return 'Alta';
        case 2:
            return 'Mitja';
        case 3:
            return 'Normal';
        case 4:
            return 'Baixa';
        case 5:
            return 'Molt baixa';
        default:
            return String(n);
    }
}
function projectDetailsUrl(projectId) {
    return `/gestio/projectes/fitxa-projecte/${encodeURIComponent(String(projectId))}`;
}
function projectPriorityLabel(n) {
    switch (n) {
        case 1:
            return 'Baixa';
        case 2:
            return 'Mitja';
        case 3:
            return 'Alta';
        case 4:
            return 'Molt alta';
        default:
            return '—';
    }
}
function projectPriorityBtn(n) {
    const label = projectPriorityLabel(n);
    // Colors Bootstrap 5 segons prioritat
    const cls = n === 1
        ? 'btn-success' // Baixa
        : n === 2
            ? 'btn-warning' // Mitja
            : n === 3
                ? 'btn-danger' // Alta
                : n === 4
                    ? 'btn-dark' // Molt alta
                    : 'btn-secondary';
    // "Botó" sense clicar (disabled)
    return `<span class="btn btn-sm ${cls} disabled" role="button" aria-disabled="true" tabindex="-1">${esc(label)}</span>`;
}
function badge(text, cls = 'text-bg-secondary') {
    return `<span class="badge ${cls}">${esc(text)}</span>`;
}
